import json

D = lambda i,t,s,e,n,c,nx: {"id":i,"text":t,"speaker":"我","avatar":"厂","score":s,"triggeredEvent":e,"historicalNote":n,"consequence":c,"nextActId":nx}
A = lambda i,t,k,tm,s,n,dls: {"id":i,"title":t,"isKeyAct":k,"timeMarker":tm,"sceneDescription":s,"npcDialogues":n,"dialogues":dls}
N = lambda sp,tx,av: {"speaker":sp,"text":tx,"avatar":av}

acts = []

# 1b
acts.append(A("act-1b","创业困境",False,"1762年",
"创业之初，你遇到了很多困难。资金紧张，机器经常出故障，工人技术不熟练。更糟糕的是，传统手工纺织业的同行们把你视为威胁，处处刁难。你能挺过这个艰难的创业期吗？",
[N("老工匠托马斯","年轻人，机器纺纱抢了我们的饭碗，我们不会让你好过的！","托"),N("妻子埃玛","亲爱的，别灰心，万事开头难。我相信你一定能成功的。","埃")],
[D("d1","我不会放弃的，越是困难越要坚持下去。",88,"你下定决心，无论遇到多大的困难都要坚持下去。你日夜钻研，改进机器，终于攻克了技术难关，工厂逐渐走上了正轨。","工业革命时期，无数创业者经历了艰难的创业过程。正是他们的坚持不懈，才推动了技术的进步和工业的发展。","坚持不懈，攻克难关","act-2"),
D("d2","我要向银行贷款，扩大生产，用规模优势打败对手。",78,"你冒险向银行贷款，扩大生产规模，试图用规模优势和更低的价格打败竞争对手。虽然风险很大，但你成功了。","工业革命时期，企业扩张主要依靠银行贷款和自身积累。敢于冒险、善于抓住机遇的企业家往往能脱颖而出。","贷款扩张，以量取胜","act-2"),
D("d3","和手工纺织业合作，让他们成为我的经销商。",85,"你决定不和手工纺织业为敌，而是和他们合作，让他们成为你的经销商。你负责生产，他们负责销售，实现了双赢。","工业革命初期，机器生产和手工生产并不是完全对立的。在很多地方，两者形成了互补关系，共同推动了经济的发展。","化敌为友，合作共赢","act-2"),
D("d4","我要申请专利，保护我的技术发明。",82,"你决定为你的技术改进申请专利，用法律保护自己的知识产权。有了专利保护，你可以放心地扩大生产，不用担心被别人模仿。","专利制度是工业革命的重要推动力。它保护了发明者的权益，激励了更多的技术创新。英国是世界上最早建立专利制度的国家之一。","申请专利，保护创新","act-2"),
D("d5","干脆放弃吧，创业太辛苦了，还是做老本行安稳。",62,"你遇到一点困难就想放弃，觉得创业太辛苦了。你关闭了工厂，重新回去做老本行。虽然生活安稳，但你心中总有一丝遗憾。","创业是艰难的，并不是所有人都能成功。有些人在困难面前选择了退缩，错过了发展的机遇。","知难而退，安稳度日","act-2"),
D("d6","我要去伦敦寻找投资，那里有更多的机会。",80,"你决定去伦敦寻找投资机会。伦敦的金融家们对你的项目很感兴趣，给你提供了资金支持。有了资金，你的工厂发展得更快了。","伦敦是当时世界的金融中心。许多工业家从伦敦的金融市场获得资金支持，推动了工业革命的发展。金融资本与工业资本的结合，是工业革命的重要特征。","伦敦融资，快速发展","act-2"),
D("d7","我要雇个能干的经理，让他帮我管理工厂。",75,"你觉得自己管理能力有限，决定聘请一个有经验的经理来帮你管理工厂。专业的管理让工厂运营得更好了，你也轻松了很多。","随着企业规模的扩大，所有权和经营权逐渐分离。专业的经理阶层开始出现，这是企业管理的一大进步。","聘请经理，专业管理","act-2"),
D("d8","我要向阿克莱特请教，他是成功的前辈。",86,"你登门拜访了阿克莱特，向他请教成功的经验。阿克莱特很欣赏你的好学精神，给了你很多宝贵的建议。","阿克莱特是英国工业革命时期的重要人物，被誉为\"工厂制度之父\"。他于1771年建立了第一家水力纺纱厂，建立了现代工厂制度的雏形。","拜访前辈，学习经验","act-2"),
D("d9","我要搞发明创造，用新技术来突破困境。",90,"你决定把精力投入到技术发明上，用新技术来突破困境。经过无数次试验，你终于发明了一种更高效的纺纱机，工厂的面貌焕然一新。","技术创新是工业革命的核心驱动力。正是无数发明家的不懈努力，才带来了一个又一个技术突破，推动了生产力的巨大发展。","技术创新，突破困境","act-2")]))

# 2b
acts.append(A("act-2b","市场竞争",False,"1775年",
"随着越来越多的工厂建立起来，市场竞争日益激烈。价格战打得不可开交，利润越来越薄。更糟糕的是，一些不良商家偷工减料，扰乱市场秩序。你如何在激烈的竞争中脱颖而出？",
[N("竞争对手法兰西斯","哈哈，你的价格太高了，没人会买你的货！看我的，比你便宜一半！","法"),N("老客户布朗","你们的质量是好，但价格实在太贵了。我打算换一家便宜的。","布")],
[D("d1","降价销售，打价格战，看谁能坚持到最后。",68,"你决定降价销售，和竞争对手打价格战。虽然暂时保住了市场份额，但利润越来越薄，几乎无利可图。","价格战是市场竞争中常见的手段。但恶性价格战往往会导致两败俱伤，最终损害整个行业的健康发展。","价格血战，两败俱伤","act-3"),
D("d2","坚持质量路线，好货不便宜，便宜没好货。",85,"你坚持走质量路线，宁愿少卖，也要保证产品质量。虽然短期销量有所下降，但逐渐赢得了口碑，高端客户都来找你进货。","质量是企业的生命线。在激烈的市场竞争中，坚持质量往往能赢得长远的发展。那些只看眼前利益、偷工减料的企业，最终会被市场淘汰。","质量取胜，赢得口碑","act-3"),
D("d3","我要开发新产品，走差异化路线。",90,"你决定开发新产品，走差异化竞争路线。你推出了几种高端面料，虽然价格高，但很受市场欢迎，利润也很丰厚。","差异化竞争是企业在激烈竞争中脱颖而出的有效策略。通过开发新产品、开辟新市场，企业可以避开价格战，获得更高的利润。","产品创新，差异化竞争","act-3"),
D("d4","联合其他工厂主，组成联盟，统一价格。",75,"你联合了几家有实力的工厂主，组成了价格联盟，共同维持市场价格。这虽然避免了恶性竞争，但也形成了垄断，损害了消费者利益。","卡特尔、辛迪加等垄断组织是资本主义发展到一定阶段的产物。它们虽然能在一定程度上避免恶性竞争，但也会形成垄断，阻碍技术进步。","价格联盟，形成垄断","act-3"),
D("d5","我要开拓海外市场，把产品卖到全世界。",88,"你决定开拓海外市场，把产品卖到欧洲大陆和美洲去。海外市场广阔，需求量大，你的工厂获得了更大的发展空间。","工业革命后，英国的商品销往世界各地。海外市场的开拓，为英国工业的发展提供了广阔的空间，也推动了殖民扩张和世界市场的形成。","开拓海外，全球布局","act-3"),
D("d6","偷工减料，降低成本，和他们拼价格。",60,"你决定偷工减料，用劣质原料降低成本，打价格战。虽然短期赚了钱，但名声臭了，客户都跑了，最后得不偿失。","偷工减料是一种短视的行为。虽然能获得一时的利益，但最终会毁坏企业的声誉，被市场所淘汰。","偷工减料，自毁长城","act-3"),
D("d7","我要建立自己的销售渠道，直接面对消费者。",82,"你决定建立自己的销售渠道，直接面向消费者销售产品。去掉了中间环节，利润更高了，也更了解市场需求。","垂直一体化是企业发展的重要策略。通过建立自己的销售渠道，企业可以更好地控制市场，提高利润。","自建渠道，直接销售","act-3"),
D("d8","我要做品牌，让大家都知道我的产品最好。",86,"你决定打造自己的品牌，投入资金做广告，宣传产品的优良品质。渐渐地，你的品牌有了知名度，产品溢价能力也提高了。","品牌建设是企业长期发展的战略。在工业革命时期，随着市场竞争的加剧，品牌的重要性日益凸显。","品牌建设，提升价值","act-3"),
D("d9","转行做别的，这行竞争太激烈了。",65,"你觉得这行竞争太激烈，赚不到钱，决定转行做别的。但每个行业都有竞争，换来换去，你最终也没有取得什么成就。","频繁转行是创业的大忌。每个行业都有竞争，只有深耕细作，才能在竞争中脱颖而出。","频繁转行，一事无成","act-3")]))

# 3b
acts.append(A("act-3b","技术抉择",False,"1785年",
"你犹豫再三，还是没有立刻采用蒸汽机。但是，看着竞争对手因为采用蒸汽机而效益大增，你开始后悔了。更让你焦虑的是，你的工厂因为技术落后，正在逐渐失去市场。现在改变主意还来得及吗？",
[N("账房托马斯","老板，再这样下去我们就要被淘汰了。要不，我们也买台蒸汽机试试？","托"),N("竞争对手的代理人","怎么样？现在知道蒸汽机的厉害了吧。不过，现在后悔可能已经晚了。","竞")],
[D("d1","亡羊补牢，犹未为晚。立刻订购蒸汽机！",85,"你决定亡羊补牢，立刻订购蒸汽机。虽然比别人晚了一步，但总比继续落后强。安装蒸汽机后，你的工厂效率大幅提升，逐渐赶上了竞争对手。","技术革新是企业生存和发展的关键。虽然起步晚了，但只要及时跟上，仍然有机会。在工业革命的浪潮中，不进则退。","亡羊补牢，后来居上","act-4"),
D("d2","还是再等等吧，蒸汽机技术还会改进的。",65,"你决定继续观望，等待蒸汽机技术进一步成熟。但技术进步的速度超出了你的预期，你的工厂越来越落后，最后被市场淘汰了。","等待技术成熟是一种保守的策略。但在技术快速发展的时代，等待往往意味着落后，最终被市场淘汰。","继续观望，错失良机","act-4"),
D("d3","我要自己研发蒸汽机，不能受制于人。",90,"你决定自己研发蒸汽机，而不是向别人购买。你投入巨资，招募优秀的工程师，终于研发出了自己的蒸汽机，还获得了专利。","自主创新是企业核心竞争力的源泉。虽然自主研发投入大、风险高，但成功后能获得巨大的竞争优势。","自主研发，掌握核心","act-4"),
D("d4","买二手蒸汽机，便宜，风险也小。",72,"你决定买一台二手蒸汽机，觉得这样既便宜又稳妥。但二手机器故障多，效率也低，经常耽误生产，你后悔贪小便宜吃大亏。","购买二手设备是一种低成本的选择。但二手设备往往效率低、故障多，长期来看可能得不偿失。","贪小便宜，吃大亏","act-4"),
D("d5","我要和其他工厂联合采购，压低价格。",78,"你联合了几家工厂一起采购蒸汽机，用批量采购来压低价格。供应商给了你们很大的折扣，大家都得到了实惠。","联合采购是中小企业降低成本的有效方式。通过集体谈判，可以获得更优惠的价格和更好的服务。","联合采购，降低成本","act-4"),
D("d6","继续用水力吧，我把工厂搬到河边去。",70,"你决定继续使用水力，把工厂搬到水力资源更丰富的地方。虽然不用买蒸汽机，但交通不便，运输成本高，也限制了工厂的发展。","水力是工业革命初期的主要动力来源。但水力受地理条件限制，工厂必须建在河边。蒸汽机的出现，彻底改变了这一局面。","搬迁工厂，依靠水力","act-4"),
D("d7","我要去瓦特的工厂参观学习，亲眼看看再说。",82,"你决定亲自去瓦特的工厂参观，亲眼看看蒸汽机的效果。这次参观让你大开眼界，你当场就订购了两台蒸汽机。","耳听为虚，眼见为实。亲自考察是做出重大决策前的重要步骤。通过实地参观，可以更直观地了解新技术的优势。","实地考察，当场决定","act-4"),
D("d8","蒸汽机太复杂了，我还是做传统生意吧。",62,"你觉得蒸汽机太复杂，风险太大，决定退出制造业，转行做传统生意。虽然避开了技术变革的风险，但也错过了工业革命的大机遇。","面对技术变革，有些人选择了退缩和逃避。他们虽然避开了风险，但也错过了发展的机遇。在历史的浪潮中，不进则退。","退缩逃避，错失机遇","act-4"),
D("d9","我要和瓦特合作，共同开发新机器。",88,"你决定和瓦特合作，共同开发和推广新机器。你提供资金和市场，瓦特提供技术。你们的合作取得了巨大的成功。","产学研合作是技术创新的有效模式。企业家和发明家的合作，可以实现优势互补，共同推动技术进步。","携手合作，共创辉煌","act-4")]))

# 7b
acts.append(A("act-7b","城市病",False,"1805年",
"工业革命带来了城市的快速扩张，但也带来了严重的\"城市病\"。住房拥挤、环境污染、疾病流行、犯罪率上升……曼彻斯特变成了一个繁荣但充满问题的城市。作为城市的一份子，你能做些什么？",
[N("医生哈维","又有霍乱病例了！这样下去，整个城市都会被感染的。必须立刻改善卫生条件！","哈"),N("警察局长威尔逊","治安越来越差了，盗窃、抢劫案层出不穷。我们警力不足，根本管不过来。","威")],
[D("d1","我要捐款改善城市卫生，这是利人利己的事。",85,"你决定捐款改善城市卫生，修建下水道和公共厕所。虽然花了不少钱，但城市的卫生条件改善了，你自己也受益。","工业革命时期，城市卫生问题非常严重。一些有社会责任感的企业家会捐款改善公共卫生条件。这既是善举，也有利于自身的健康和企业的发展。","捐款改善卫生，利人利己","act-8"),
D("d2","这是政府的事，和我没关系。我管好自己就行了。",65,"你觉得城市问题是政府的责任，和你没关系。你只关心自己的工厂和生意，对公共事务漠不关心。","在工业革命时期，很多资本家只关心自己的利益，对公共事务漠不关心。这也是城市问题日益严重的原因之一。","事不关己，高高挂起","act-8"),
D("d3","我要搬到郊区去住，远离这些城市病。",68,"你受不了城市的脏乱差，决定搬到郊区去住。虽然每天上下班麻烦一点，但至少住得舒服。","随着城市问题的加剧，富裕阶层开始向郊区迁移。这就是后来的\"郊区化\"现象。富人搬走了，城市中心变得更加衰败。","移居郊区，远离喧嚣","act-8"),
D("d4","我要投资房地产，建更多的工人住宅。",78,"你看到了住房需求的商机，决定投资房地产，建设更多的工人住宅。虽然每套房子很小很简陋，但因为需求量大，你还是赚了不少钱。","城市化带来了巨大的住房需求。一些资本家投资房地产，建设工人住宅。虽然住房条件很差，但他们也从中赚取了高额利润。","投资房产，赚取利润","act-8"),
D("d5","我要建立工厂医院，为工人提供医疗服务。",88,"你决定在工厂建立医院，为工人提供医疗服务。这不仅保障了工人的健康，也提高了生产效率。你的做法还带动了其他工厂主效仿。","工业革命时期，工人的医疗条件非常差。一些有远见的工厂主开始为工人提供医疗服务。这既是人道关怀，也有利于提高生产效率。","建立医院，保障健康","act-8"),
D("d6","我要组织志愿巡逻队，维护社区治安。",75,"你组织了志愿巡逻队，和其他工厂主一起维护社区治安。虽然不是正式的警察队伍，但对改善治安还是起到了一定作用。","在警力不足的情况下，一些社区会组织志愿巡逻队来维护治安。这是公民自助的一种形式。","志愿巡逻，维护治安","act-8"),
D("d7","我要研究城市规划，提出改善方案。",82,"你开始研究城市规划，希望从根本上解决城市问题。你提出了一套改善方案，虽然没有被完全采纳，但也推动了城市的改造。","城市规划是一门古老而又年轻的学科。工业革命后，城市问题日益严重，城市规划作为一门独立学科逐渐发展起来。","研究规划，提出方案","act-8"),
D("d8","让工人住在工厂里，这样就不用管城市的问题了。",72,"你决定让工人住在工厂宿舍里，这样他们就不用在城市里租房，也减少了和社会的接触。虽然方便了管理，但工人的生活圈子太窄了。","早期很多工厂都提供宿舍，把工人集中管理。这既是为了方便，也是为了控制工人。工人的生活几乎完全被工厂包围。","集中管理，工厂宿舍","act-8"),
D("d9","我要创办一份报纸，呼吁社会关注城市问题。",80,"你创办了一份报纸，专门报道和讨论城市问题，呼吁社会关注和改善。报纸产生了很大的社会影响，推动了问题的解决。","新闻媒体在推动社会进步方面发挥了重要作用。通过揭露问题、引导舆论，媒体可以推动政府和社会采取行动。","创办报纸，推动改革","act-8")]))

# 10b
acts.append(A("act-10b","政治参与",False,"1835年",
"议会改革后，工业资产阶级获得了更多的政治权利。作为有影响力的工厂主，你也开始参与政治。但是，政治比你想象的要复杂得多。你能在政治舞台上发挥作用吗？",
[N("政治盟友格雷","老兄，进入议会只是第一步。政治斗争复杂得很，你要学的东西还多着呢。","格"),N("政治对手皮尔","哼，一个暴发户也想玩政治？我会让你知道什么叫规矩。","皮")],
[D("d1","我要好好学习政治，做一个合格的议员。",85,"你决定认真学习政治知识，努力做一个合格的议员。你虚心向资深政治家请教，逐渐掌握了政治斗争的技巧。","工业资产阶级进入议会后，经历了一个学习和适应的过程。他们逐渐掌握了政治运作的规则，在政治舞台上发挥着越来越重要的作用。","认真学习，合格议员","act-11"),
D("d2","政治就是利益交换。我用钱开路，没有办不成的事。",62,"你认为政治就是利益交换，有钱就能搞定一切。你用金钱收买议员和官员，虽然办成了一些事，但名声很臭，最终还差点因腐败被调查。","金钱政治是资本主义民主的痼疾。虽然法律禁止贿赂，但利益交换以各种更隐蔽的方式存在着。","金钱开路，腐败丑闻","act-11"),
D("d3","我要推动经济立法，为工业发展创造更好的环境。",88,"你决定把主要精力放在推动经济立法上，为工业发展创造更好的政策环境。你在议会中发挥了重要作用，推动了多项有利的法案通过。","工业资产阶级在政治上的主要诉求是经济自由主义。他们要求废除重商主义政策，实行自由贸易，为资本主义发展扫清道路。","推动立法，促进发展","act-11"),
D("d4","我要为工人说话，虽然我是工厂主。",90,"你虽然是工厂主，但经常在议会中为工人说话，主张改善工人待遇。你的立场让很多人感到意外，也赢得了工人的尊重。","历史上，并不是所有的资产阶级都只关心自己的利益。一些有良知的政治家，即使出身资产阶级，也会为弱势群体说话。","为民请命，赢得尊重","act-11"),
D("d5","政治太脏了，我还是专心做生意吧。",70,"你觉得政治太肮脏复杂，决定退出政坛，专心做生意。虽然失去了政治影响力，但你把企业经营得很好。","并不是所有的企业家都适合从政。有些人选择专注于商业，在经济领域发挥作用。这也是一种贡献。","退出政坛，专注商业","act-11"),
D("d6","我要组建自己的政党，代表工业资产阶级的利益。",82,"你决定组建一个新的政党，代表工业资产阶级的利益。虽然建党过程很艰难，但你的政党逐渐在政治舞台上占有了一席之地。","政党是现代政治的重要产物。不同的阶级和利益集团通过组建政党来参与政治，表达自己的诉求。","组建政党，代表利益","act-11"),
D("d7","我要去美国考察政治制度，学习他们的经验。",78,"你决定去美国考察政治制度，学习他们的民主经验。美国的政治制度让你大开眼界，也让你对英国的政治有了新的思考。","美国的民主制度对世界各国都产生了深远影响。很多欧洲人会去美国考察，学习他们的政治经验。","赴美考察，学习民主","act-11"),
D("d8","我要支持教育改革，提高国民素质。",85,"你认为教育是国家富强的根本，决定大力支持教育改革。你推动通过了多项教育法案，为国民教育的发展做出了贡献。","教育是国家发展的基础。工业革命后，对劳动者素质的要求越来越高，国民教育的重要性日益凸显。","支持教育，提高素质","act-11"),
D("d9","政治不就是拉关系吗？我有的是人脉。",68,"你认为政治就是靠关系，你凭借广泛的人脉在议会中混得风生水起。但你没有真才实学，遇到真正的问题时就束手无策了。","在政治中，人脉关系固然重要，但更重要的是能力和见识。只靠关系，是走不远的。","人脉政治，缺乏真才","act-11")]))

# 14b
acts.append(A("act-14b","危机对策",False,"1847年",
"经济危机越来越严重了。你的工厂虽然还在勉强维持，但也是举步维艰。工人们的生活越来越困难，社会动荡不安。在这个困难时期，你会做出怎样的选择？",
[N("工人代表约翰","老板，我们实在活不下去了。工资一降再降，物价却在涨。求求你，给我们加点工资吧。","约"),N("银行家史密斯","先生，你的工厂目前状况不佳，我们很难再给你提供贷款了。你得自己想办法。","史")],
[D("d1","再难也不能亏待工人。我就是卖厂房，也要给工人发工资。",92,"你决定无论多么困难，也不能亏待工人。你变卖了一些资产，坚持给工人发工资。工人们非常感动，和你一起共渡难关。","在经济危机的艰难时刻，企业家的选择最能体现其品格。那些坚持善待工人、与员工共渡难关的企业家，最终往往能赢得尊重和长远的发展。","共渡难关，感人至深","act-15"),
D("d2","没办法，只能降薪裁员，先保住企业再说。",65,"迫于压力，你不得不降低工人工资，裁减部分员工。虽然保住了企业，但看着那些失业的工人，你心里也很不是滋味。","经济危机时期，企业为了生存，往往会采取降薪裁员的措施。这虽然是无奈之举，但也会给工人带来巨大的痛苦。","降薪裁员，无奈之举","act-15"),
D("d3","我要转型生产必需品，危机时期必需品不会滞销。",85,"你决定转型生产生活必需品，因为不管经济多么困难，人们总得吃饭穿衣。转型后，你的工厂果然恢复了生机。","经济危机时期，生产奢侈品的企业受到的冲击最大，而生产生活必需品的企业则相对稳定。及时转型是企业度过危机的有效策略。","灵活转型，生产必需品","act-15"),
D("d4","我要去殖民地开拓市场，那边受危机影响小。",80,"你决定去殖民地开拓新市场，认为那边受经济危机的影响较小。殖民地市场确实帮你缓解了危机，但也让你卷入了殖民扩张的漩涡。","工业革命后，殖民地成为资本主义国家转嫁危机的重要场所。通过向殖民地倾销商品、掠夺原料，资本主义国家得以缓解国内的经济危机。","开拓殖民，转嫁危机","act-15"),
D("d5","危机中有机遇，我要趁机收购那些倒闭的企业。",88,"你看到了危机中的机遇，决定趁机低价收购那些经营不善的企业。等危机过去，你的企业规模扩大了好几倍。","经济危机既是挑战也是机遇。有实力的企业会在危机中并购扩张，实现低成本扩张。这就是所谓的\"危中有机\"。","趁机并购，做大做强","act-15"),
D("d6","我要申请破产，这样可以保住我剩下的财产。",62,"你决定申请破产，用法律手段保护自己剩下的财产。虽然你保住了一部分钱，但你的名声和事业都毁了。","破产保护是企业面临危机时的一种选择。虽然能保住部分财产，但也意味着企业的失败。","申请破产，保住财产","act-15"),
D("d7","我要和工人一起商量，共同寻找度过危机的办法。",86,"你决定坦诚地告诉工人工厂的困难，和他们一起商量度过危机的办法。工人们提出了很多好建议，大家齐心协力，终于熬过了危机。","民主管理、共商共议是应对危机的好方法。当员工了解到企业的真实情况后，往往会主动承担责任，和企业共渡难关。","共商对策，齐心协力","act-15"),
D("d8","我要搞技术革新，用新技术降低成本，提高竞争力。",90,"你决定加大技术研发投入，用新技术降低成本，提高产品竞争力。虽然短期投入大，但新技术让你的企业在危机后更具竞争力。","技术创新是企业核心竞争力的源泉。在危机中坚持技术创新的企业，往往能在危机后脱颖而出，获得更大的发展。","技术革新，化危为机","act-15"),
D("d9","我太老了，把企业交给年轻人吧。",72,"你觉得自己年纪大了，应对不了这么复杂的局面，决定把企业交给年轻人。年轻人有新思想新方法，也许能把企业带出新的天地。","企业的新老交替是不可避免的。老一辈创业者打下基础，新一代人继续发展，这是企业传承的正常规律。","新老交替，薪火相传","act-15")]))

# 16b
acts.append(A("act-16b","工会斗争",False,"1866年",
"工会的力量越来越强大了。他们不仅要求提高工资、缩短工时，还开始参与工厂管理。作为工厂主，你感到自己的权威受到了挑战。你会如何应对工会的挑战？",
[N("工会主席琼斯","先生，我们要求参与工厂管理，工人有权利知道企业的经营状况。","琼"),N("工厂主同行布朗","绝对不能让步！让工人参与管理，那我们还是老板吗？","布")],
[D("d1","我同意让工人参与管理，大家一起把企业办好。",90,"你做出了一个大胆的决定——同意让工人代表参与工厂管理。虽然一开始有很多摩擦，但渐渐地，劳资双方找到了合作的方式，企业发展得更好了。","工人参与管理是工业民主的重要形式。虽然在19世纪还不普遍，但一些有远见的企业家已经开始尝试。实践证明，让工人参与管理有利于激发员工的积极性和创造性。","工人参与，共同管理","act-17"),
D("d2","绝不可能！工厂是我的，我说了算。",60,"你坚决拒绝了工会的要求，认为工厂是你的私人财产，你想怎么管就怎么管。你的态度激怒了工人，一场大罢工爆发了。","早期资本家通常把企业视为自己的私人领地，拒绝工人参与管理。但这种专制的管理方式，往往会激起工人更强烈的反抗。","拒绝参与，引发罢工","act-17"),
D("d3","可以让他们提意见，但决策权必须在我手里。",75,"你同意听取工人的意见，但坚持最终决策权必须掌握在自己手里。这是一种妥协方案，虽然工人不完全满意，但至少有了表达的渠道。","决策权是企业管理的核心问题。让工人提意见但保留最终决策权，是一种比较常见的妥协方式。","听取意见，保留决策权","act-17"),
D("d4","我要建立职工持股计划，让工人成为企业的主人。",92,"你决定实行职工持股计划，让工人持有公司股份，真正成为企业的主人。这虽然是一个非常激进的尝试，但极大地调动了工人的积极性。","职工持股是一种让工人参与企业所有权的制度安排。虽然在19世纪还很少见，但它代表了一种进步的方向。","职工持股，真正当家","act-17"),
D("d5","用糖衣炮弹腐蚀工会领袖，让他们为我说话。",65,"你决定用金钱和好处收买工会领袖，让他们站在你这边。这招确实有效，工会变得温和多了，但工人们渐渐发现了真相，对工会领袖失去了信任。","收买工会领袖是资本家对付工人运动的常用手段之一。通过培养工人贵族，资产阶级可以在一定程度上控制和分化工人运动。但这种手段终究是不光彩的。","收买领袖，分化工人","act-17"),
D("d6","我要研究一下合作社模式，看看能不能把工厂改成合作社。",88,"你开始研究工人合作社模式，考虑把工厂改成工人合作社，让工人自己管理自己。这是一个非常激进的想法，但也许能从根本上解决劳资矛盾。","工人合作社是一种工人集体所有、民主管理的企业形式。空想社会主义者欧文等人就积极倡导和实践合作社运动。虽然合作社没有成为主流，但它提供了一种替代资本主义的可能性。","研究合作，探索新路","act-17"),
D("d7","引进更多机器，减少对工人的依赖，看他们还怎么闹。",78,"你决定引进更多自动化机器，减少对工人的依赖，从而削弱工会的谈判力量。技术进步确实让你减少了对人工的依赖，但也带来了新的问题。","技术进步是一把双刃剑。它既提高了生产力，也会对就业和劳资关系产生深远影响。用机器代替人工，是资本家对付工人运动的手段之一。","机器换人，削弱工会","act-17"),
D("d8","我要聘请专业的人力资源经理，用科学的方法管理工人。",82,"你决定聘请专业的人力资源经理，用更科学、更人性化的方法来管理工人。专业的管理让劳资关系改善了很多，工人的满意度也提高了。","人力资源管理是现代企业管理的重要组成部分。随着企业的发展，传统的专制管理方式越来越不适应了，专业化、人性化的管理成为趋势。","专业管理，改善关系","act-17"),
D("d9","算了，把工厂卖了，我受够了这些烦心事。",62,"你厌倦了和工会斗智斗勇的日子，决定把工厂卖掉，过轻松的退休生活。虽然不用再操心了，但你心里还是有些失落。","面对劳资矛盾和经营压力，有些资本家选择退出。卖掉企业，享受生活，也是一种人生选择。","卖掉工厂，轻松退休","act-17")]))

# 17b
acts.append(A("act-17b","国际风云",False,"1868年",
"第一国际的影响越来越大，各国工人运动风起云涌。与此同时，欧洲的政治格局也在发生深刻变化。德国统一在即，法国危机四伏。在这个动荡的时代，你的命运将和整个欧洲紧紧联系在一起。",
[N("记者恩格斯（化名）","先生，您对当前的欧洲局势怎么看？您认为工人运动的未来会怎样？","恩"),N("银行家罗斯柴尔德","欧洲的局势很不稳定啊。战争一触即发，我们做生意的，得早做准备。","罗")],
[D("d1","我看好工人运动的未来，这是历史的潮流。",85,"你认为工人运动是历史发展的潮流，是不可阻挡的。虽然道路是曲折的，但前途是光明的。你对未来持乐观态度。","工人运动是近代历史发展的重要潮流。尽管经历了很多挫折和失败，但工人阶级争取自身解放的斗争是不可阻挡的。","看好工人，顺应潮流","act-18"),
D("d2","工人运动成不了气候，成不了大事。",65,"你对工人运动持轻视态度，认为他们成不了气候。但历史的发展出乎你的意料，工人运动越来越强大，深刻地改变了社会。","对工人运动的轻视是资产阶级的通病。他们往往低估了工人阶级的力量和历史的进步潮流。","轻视工人，误判形势","act-18"),
D("d3","战争要来了，我要赶紧把资产转移到安全的地方。",70,"你预感战争即将来临，决定把资产转移到相对安全的英国本土。虽然转移资产损失了一些，但保住了大部分财富。","战争会对经济和财富造成巨大冲击。在战争来临前转移资产，是资本家常见的自保行为。","预感战争，转移资产","act-18"),
D("d4","战争是发财的好机会，我要投资军工产业。",72,"你认为战争是发财的好机会，决定投资军工产业。战争爆发后，你的军工厂订单爆满，发了一大笔战争财。","战争会带来巨大的军火需求。一些资本家会在战争中大发横财。这就是所谓的\"发战争财\"。","投资军工，发战争财","act-18"),
D("d5","我要致力于和平，反对战争。",88,"你是一个和平主义者，坚决反对战争。你积极参与和平运动，呼吁各国通过和平方式解决争端。虽然没有能够阻止战争，但你的努力是有意义的。","和平是人类的共同愿望。历史上有很多和平主义者，为了反对战争、维护和平做出了不懈的努力。","致力和平，反对战争","act-18"),
D("d6","我要去美国发展，那里远离欧洲的纷争。",68,"你对欧洲的动荡感到厌倦，决定移民美国，远离这些纷争。美国虽然也有它的问题，但至少远离了欧洲的战火。","19世纪，大量欧洲人移民美国，其中包括很多为了躲避战乱和政治迫害的人。美国被视为\"新世界\"，充满了机遇和希望。","移民美国，远离纷争","act-18"),
D("d7","我要写一本书，分析欧洲的局势和未来。",80,"你决定写一本书，分析当前的欧洲局势和未来的发展趋势。你的书出版后引起了很大反响，你也成了有名的时事评论家。","19世纪是一个思想活跃的时代。很多人著书立说，分析时局，预测未来。这些著作对后世产生了深远的影响。","著书立说，分析时局","act-18"),
D("d8","我要和各国工人组织建立联系，支持他们的斗争。",90,"你决定和各国工人组织建立联系，积极支持他们的斗争。你不仅提供资金援助，还利用自己的影响力为工人运动发声。","工人运动是国际性的。各国工人阶级的斗争相互支持、相互促进。第一国际就是国际工人联合的重要组织。","国际联合，支持斗争","act-18"),
D("d9","天下大势，合久必分，分久必合。顺其自然吧。",75,"你对历史的发展持一种顺其自然的态度。你认为个人的力量是有限的，历史有它自己的规律。你能做的，就是做好自己的事。","历史的发展有其客观规律。个人在历史大潮中，往往只能顺应潮流。但这并不意味着个人是无能为力的。","顺应历史，顺其自然","act-18")]))

# 19b
acts.append(A("act-19b","新时代",False,"1871年",
"巴黎公社失败了，但它像一盏明灯，照亮了无产阶级解放的道路。马克思主义广泛传播，工人政党在各国纷纷建立。一个新的时代——帝国主义和无产阶级革命的时代，正在到来。站在时代的门槛上，你有什么感想？",
[N("年轻工人威廉","我们这一代人，一定要实现公社未竟的事业！共产主义一定会实现！","威"),N("老朋友乔治","老伙计，我们这一代人快要退场了。未来是年轻人的，希望他们能生活在一个更好的世界。","乔")],
[D("d1","我相信未来会更好，共产主义一定会实现。",92,"你对未来充满信心，坚信共产主义一定会实现。虽然你可能看不到那一天，但你愿意为这个伟大的理想贡献自己的一份力量。","共产主义是人类最崇高的社会理想。尽管道路是曲折的，但前途是光明的。一代又一代的革命者，为了这个理想前赴后继，不懈奋斗。","坚信未来，投身理想","act-end"),
D("d2","未来会怎样，谁知道呢？过好当下就行了。",70,"你对未来没有太多的想法，觉得过好当下的生活就够了。你不关心什么理想信念，只想过好自己的小日子。","每个人都有选择自己生活方式的权利。有些人胸怀大志，心系天下；有些人则更关注当下的生活。这没有绝对的对错。","活在当下，知足常乐","act-end"),
D("d3","我要把我的一生写下来，留给后人。",82,"你决定写一本回忆录，把自己一生的经历和思考记录下来，留给后人。这本书后来成为研究工业革命时代的重要史料。","回忆录是历史的重要见证。个人的经历，反映的是整个时代的变迁。很多历史细节，正是通过个人的回忆流传下来的。","撰写回忆，记录时代","act-end"),
D("d4","我要创办一份刊物，继续宣传马克思主义。",88,"你决定创办一份刊物，继续宣传马克思主义，为工人运动提供理论指导。虽然遇到了很多困难，但你坚持了下来，影响了一代又一代的工人。","报刊是宣传革命理论的重要阵地。在马克思主义传播的过程中，革命报刊发挥了重要作用。","创办刊物，传播真理","act-end"),
D("d5","我已经老了，未来是年轻人的。我相信他们。",85,"你觉得自己已经老了，未来是属于年轻人的。你对年轻一代充满信心，相信他们一定能够开创一个更加美好的未来。","长江后浪推前浪，一代新人换旧人。每一代人都有自己的使命，历史的接力棒终将交到年轻人手中。","相信青年，寄望未来","act-end"),
D("d6","我要建立一个基金会，资助工人运动和进步事业。",90,"你决定拿出自己的大部分财产，建立一个基金会，专门资助工人运动和进步事业。你的善举，为革命事业提供了重要的物质支持。","物质支持是革命事业发展的重要保障。很多进步人士和同情革命的有产者，都曾以各种方式为工人运动提供资助。","建立基金，支持革命","act-end"),
D("d7","人生苦短，及时行乐。我要好好享受剩下的时光。",65,"你觉得人生苦短，应该及时行乐。你决定用剩下的时间好好享受生活，不再为那些理想和主义操心。","人生的意义是什么？不同的人有不同的答案。有些人追求享乐，有些人追求理想。这是每个人自己的选择。","及时行乐，享受人生","act-end"),
D("d8","我要去世界各地看看，开阔一下眼界。",78,"你决定去世界各地旅行，看看不同的国家和人民。这次旅行让你大开眼界，也让你对人类的未来有了更多的思考。","旅行是开阔眼界、增长见识的好方式。通过观察不同的社会和文化，我们可以更好地理解这个世界。","周游世界，开阔眼界","act-end"),
D("d9","历史是螺旋式上升的。道路曲折，前途光明。",85,"你认为历史的发展是螺旋式上升的，前进中有曲折，曲折中向前进。虽然巴黎公社失败了，但历史的总趋势是不会改变的。","唯物辩证法认为，事物的发展是前进性和曲折性的统一。前途是光明的，道路是曲折的。这是历史发展的辩证法。","辩证看待，前途光明","act-end")]))

# 20b
acts.append(A("act-20b","工业巨子",False,"1870年",
"经过几十年的奋斗，你的企业已经发展成为曼彻斯特最大的纺织企业之一。你从一个普通的创业者，变成了名副其实的工业巨子。站在你巨大的工厂前，你会想些什么？",
[N("经理威廉姆斯","老板，我们的工厂现在是全曼彻斯特最大的了！您的创业故事，已经成为大家学习的榜样。","威"),N("年轻学徒汤姆","老板，我以后也要成为像您一样成功的人！您能告诉我成功的秘诀是什么吗？","汤")],
[D("d1","成功的秘诀就是勤奋、坚持和眼光。",85,"你告诉年轻人，成功没有秘诀，就是靠勤奋、坚持和眼光。只要肯努力，抓住机遇，每个人都有成功的可能。","勤奋和坚持是成功的基石。在工业革命时代，无数人通过自己的努力奋斗，改变了命运，成就了事业。","勤奋坚持，成功秘诀","act-end"),
D("d2","我的成功，离不开工人们的辛勤劳动。",90,"你说，你的成功不仅仅是你个人的，更离不开全体工人的辛勤劳动。你决定拿出一部分利润，改善工人的生活和工作条件。","一个企业家的成功，离不开员工的辛勤付出。懂得感恩、善待员工的企业家，才会赢得真正的尊重。","感恩员工，回馈社会","act-end"),
D("d3","我成功了，但也失去了很多。人生没有完美。",80,"你虽然取得了巨大的成功，但也失去了很多——陪伴家人的时间、健康的身体、简单的快乐。你感叹，人生没有完美。","事业成功和生活幸福并不总是一致的。很多人为了事业，牺牲了家庭、健康和个人生活。这是一种遗憾。","得失之间，人生缺憾","act-end"),
D("d4","我要继续扩大生产，建立我的工业帝国。",78,"你的野心不止于此。你决定继续扩大生产，向其他行业进军，建立一个庞大的工业帝国。你的事业，还在继续发展。","企业家的精神是永不满足。不断进取、勇攀高峰，是企业家的重要特质。","继续进取，工业帝国","act-end"),
D("d5","我要做慈善，回报社会。",88,"你决定投身慈善事业，用自己的财富回报社会。你捐建学校、医院、图书馆，为社会做出了巨大的贡献。","达则兼济天下。很多成功的企业家在积累了财富之后，会投身慈善事业，回报社会。","投身慈善，回报社会","act-end"),
D("d6","我要把企业交给儿子，自己退休享福。",72,"你决定把企业交给儿子管理，自己退休享福。辛苦了一辈子，是时候该享受一下生活了。","企业传承是一个重要的问题。很多家族企业会选择子承父业的方式，将事业延续下去。","退休享福，传承事业","act-end"),
D("d7","我要著书立说，把我的经验分享给更多人。",82,"你决定写一本关于创业和管理的书，把自己的经验和思考分享给更多的人。你的书出版后很受欢迎，激励了很多年轻人。","经验的分享是宝贵的。成功人士的经验和思考，可以给后来者很多启发和帮助。","著书立说，分享经验","act-end"),
D("d8","我要从政，在更广阔的舞台上发挥作用。",75,"你决定从政，利用自己的财富和影响力，在政治舞台上发挥更大的作用。你希望能推动社会的进步和改革。","很多企业家在事业成功之后，会转向政治领域，希望在更大的舞台上实现自己的抱负。","从政为官，更大舞台","act-end"),
D("d9","这一切都只是开始。未来还有无限可能。",86,"你认为现在的成就只是一个开始，未来还有无限的可能。你对未来充满期待，准备迎接新的挑战。","成功不是终点，而是新的起点。永不止步、永远向前，才能不断创造新的辉煌。","永不止步，未来可期","act-end")]))

print(f"第七组生成完成，共 {len(acts)} 幕")

